import "./styles/Login.css";
import { useNavigate } from "react-router-dom";
import { useState } from "react";
import api from "../api/axios";

function Login() {
  const navigate = useNavigate();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("Student");
  const [genre, setGenre] = useState(""); // ✅ FIXED
  const [error, setError] = useState("");

  const handleLogin = async () => {
    try {
      setError("");

      // send genre ONLY if librarian
      const data = { email, password, role };
      if (role === "Librarian") {
  data.genre = genre.trim().toLowerCase();
}

      // ⚠️ api already has /api in baseURL
      const res = await api.post("/auth/login", data);

      const { name, role: userRole, genre: userGenre } = res.data;

      if (userRole === "Student") {
        navigate("/student-dashboard", { state: { name } });
      } else // AFTER const { name, role: userRole, genre: userGenre } = res.data;

if (userRole === "Librarian") {
  // 🔥 FORCE-CLEAN GENRE FORMAT
  const fixedGenre =
    userGenre.charAt(0).toUpperCase() +
    userGenre.slice(1).toLowerCase();

  localStorage.setItem("role", "Librarian");
  localStorage.setItem("genre", fixedGenre);

  navigate("/librarian-dashboard", {
    state: { genre: fixedGenre }
  });




  
      } else if (userRole === "Admin") {
        navigate("/admin-dashboard");
      }
    } catch (err) {
      setError("Invalid login credentials");
    }
  };

  return (
    <div className="login-wrapper">
      <div className="login-card">
        <h2>Login</h2>

        {error && <p className="error">{error}</p>}

        <input
          type="email"
          placeholder="University Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />

        <input
          type="password"
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />

        <select value={role} onChange={(e) => setRole(e.target.value)}>
          <option>Student</option>
          <option>Librarian</option>
          <option>Admin</option>
        </select>

        {/* 🔥 Genre only when Librarian */}
        {role === "Librarian" && (
          <input
            type="text"
            placeholder="Genre"
            value={genre}
            onChange={(e) => setGenre(e.target.value)}
          />
        )}

        <button className="login-btn" onClick={handleLogin}>
          Login
        </button>
      </div>
    </div>
  );
}

export default Login;
